#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int A, B;
        scanf("%d %d", &A, &B);
        long long sum = 0;
        for (int N = A; N <= B; N++) {
            int S_N = 0;
            int temp = N;
            while (temp > 0) {
                int digit = temp % 10;
                if (digit % 2 == 1) {
                    S_N += digit;
                } else {
                    S_N += 2 * digit;
                }
                temp /= 10;
            }
            sum += S_N % 10;
        }
        printf("%lld\n", sum);
    }
    return 0;
}

