const readline = () => lines[idx++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const [A, B] = readline().split(' ').map(Number);
    let sum = 0;
    for (let N = A; N <= B; N++) {
        let S_N = 0;
        let temp = N;
        while (temp > 0) {
            let digit = temp % 10;
            if (digit % 2 === 1) {
                S_N += digit;
            } else {
                S_N += 2 * digit;
            }
            temp = Math.floor(temp / 10);
        }
        sum += S_N % 10;
    }
    console.log(sum);
}
